local a = _G[script]
local g = {}
local tf = a.import(script, script, "with-hooks")
local tg = tf.withHooks
local th = tf.withHooksPure
for J, K in pairs(a.import(script, script, "hooks")) do
	g[J] = K
end
local function i(ti)
	return tg(ti)
end
local function l5(ti)
	return th(ti)
end
g.hooked = i
g.pure = l5
return g
